long minNonZeroProduct(int p) {
    final long MOD = 1000000007;
    long prod = 1;
    long a = (1L << p) - 2;
    long b = ((1L << p) - 1) % MOD;

    while (a > 0) {
        if (a % 2 == 1) {
            prod = (prod * b) % MOD;
        }
        b = (b * b) % MOD;
        a /= 2;
    }
    return prod;
}
